doInstall=async function(){
  let bundle=check(work.payload);
  for(let input of root.querySelectorAll('[data-character-gallery]')){
    let resource=bundle.resources[+input.dataset.characterGallery];
    if(resource?.kind==='character'&&resource.character)resource.character.gallery=input.value;
  }
  let selected=[...root.querySelectorAll('[data-i]:checked')].map(input=>({resource:bundle.resources[+input.dataset.i],index:+input.dataset.i})).filter(item=>item.resource);
  if(!selected.length)throw Error('请至少选择一项内容。');
  if(!o.bridge)throw Error('当前环境未连接状态栏安装接口，请关闭工坊后从状态栏云朵重新打开。');
  let before=await o.bridge.snapshotInstallState?.()||{};
  for(let {resource,index} of selected){
    let one={format:F,version:2,kind:resource.kind,metadata:bundle.metadata,resources:[resource]};
    let enabled=root.querySelector(`[data-enable-after-install="${index}"]`)?.checked===true;
    if(resource.kind==='character')await o.bridge.importCharacterPackage(one);
    else if(resource.kind==='worldbook')await o.bridge.importWorldbookWork(one);
    else if(resource.kind==='generator')await o.bridge.importGenerators(resource.definitions);
    else if(resource.kind==='regex')await o.bridge.importRegexes(resource.regexes,{enabled});
    else if(resource.kind==='script')await o.bridge.importScripts(resource.scripts,{enabled});
    else if(resource.kind==='fengyue-item')await o.bridge.importFengyueItems(resource.items);
  }
  let after=await o.bridge.snapshotInstallState?.()||{},resources=selected.map(item=>({kind:item.resource.kind,name:item.resource.name})),record={id:`${work.id}-${Date.now()}`,workId:work.id,title:work.title,installedAt:new Date().toISOString(),resources,delta:installDelta(before,after)};
  saveInstalledWorks([record,...installedWorks()]);root.querySelector('.workshop-dialog')?.remove();root.querySelector('.modal')?.remove();
  let updated=await api('/api/works/'+encodeURIComponent(work.id)+'/download',{method:'POST'});work.downloads=updated.downloads;workshopToast(`已安装 ${selected.length} 项内容，并加入“我的下载”`,'ok','安装完成');
};
